import { Component, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink, ActivatedRoute } from '@angular/router';
import { ProductService } from '../../core/services/product.service';
import { CartService } from '../../core/services/cart.service';
import { MoneyPipe } from '../../core/pipes/money.pipe';
import { Product } from '../../core/models';

@Component({
  selector: 'app-product-detail',
  standalone: true,
  imports: [CommonModule, RouterLink, MoneyPipe],
  templateUrl: './product-detail.component.html',
  styleUrl: './product-detail.component.css',
})
export class ProductDetailComponent {
  readonly product = signal<Product | undefined>(undefined);
  readonly qty = signal(1);
  readonly added = signal(false);

  constructor(
    private route: ActivatedRoute,
    private productService: ProductService,
    private cart: CartService,
  ) {
    const id = this.route.snapshot.paramMap.get('id');
    if (id) this.product.set(this.productService.getById(id));
  }

  changeQty(delta: number): void {
    const p = this.product();
    if (!p) return;
    const next = Math.min(Math.max(1, this.qty() + delta), Math.max(1, p.stockQty));
    this.qty.set(next);
  }

  addToCart(): void {
    const p = this.product();
    if (!p || p.stockQty <= 0) return;
    this.cart.addItem(p, this.qty());
    this.added.set(true);
  }
}
